pub fn sort_by_tip(&mut self, base_fee: u64) {
    self.bundles.sort_by(|a, b| {
        let tip_a = a.effective_tip_per_gas(base_fee).unwrap_or(0);
        let tip_b = b.effective_tip_per_gas(base_fee).unwrap_or(0);
        tip_b.cmp(&tip_a)
    });
}

